create table account
(
    id                      char(20) not null comment 'ID'
        primary key,
    user                    char(20) not null comment '账号',
    password                char(20) not null comment '密码',
    personal_information_id char(20) not null comment '个人信息表 ID',
    is_delete               int      not null comment '逻辑删除 0存在，1删除',
    create_time             datetime not null comment '创建时间',
    create_user             char(20) not null comment '创建人',
    update_time             datetime not null comment '修改时间',
    update_user             char(20) not null comment '修改人',
    constraint personal_information_id
        unique (personal_information_id),
    constraint user
        unique (user)
)
    comment '账号';

